dtsPropsFor.SearchInput:
/** Controlled input value. */
value: string;
placeholder?: string;
/** Fired on every keystroke and when the clear button is pressed (emits ''). */
onChange: (value: string) => void;

dtsPropsFor.Pagination:
currentPage: number;
totalPages: number;
/** Renders nothing when totalPages <= 1. Changing page also scrolls to top. */
onPageChange: (page: number) => void;

dtsPropsFor.TechIcon:
/** Ordered icon sources, each `"<provider>:<slug>"` (provider: simple-icons | thesvg | iconify). First resolvable wins. */
slugs?: string[] | null;
/** Used for the fallback initial when no icon resolves. */
label?: string | null;
/** Icon box size in px (default 32). */
size?: number;
/** When true (default), renders nothing if no icon resolves; otherwise shows the label initial. */
hideIfNotFound?: boolean;

dtsPropsFor.KeywordTechRankingCardList:
title: string;
items: Array<{
  keyword_group: string;
  label: string;
  icon_slugs?: string[] | null;
  tags?: string[] | null;
  job_count: number;
}>;
loading: boolean;
/** Called on mount and whenever the category tab changes. */
getItems: (category: string) => void;
/** Optional "more" link target. */
moreTo?: string;
/** Slot rendered next to the title. */
titleHint?: React.ReactNode;
/** Override the default job-count metric per item. */
renderMetric?: (item: { keyword_group: string; label: string; job_count: number }) => React.ReactNode;
